from flask import Flask, redirect, request, session, url_for
import requests

app = Flask(__name__)
app.secret_key = 'your_secret_key'

# Replace with your OAuth 2.0 provider's details
AUTHORIZE_URL = 'https://oauth-provider.com/authorize'
TOKEN_URL = 'https://oauth-provider.com/token'
CLIENT_ID = 'your_client_id'
CLIENT_SECRET = 'your_client_secret'

@app.route('/login')
def login():
    state = 'random_state_string'  # Generate a secure random string
    session['state'] = state
    params = {
        'response_type': 'code',
        'client_id': CLIENT_ID,
        'redirect_uri': url_for('callback', _external=True),
        'scope': 'openid email profile',
        'state': state
    }
    return redirect(AUTHORIZE_URL + '?' + '&'.join([f'{k}={v}' for k, v in params.items()]))

@app.route('/callback')
def callback():
    if request.args.get('state') != session.pop('state', None):
        return 'Invalid state parameter', 400

    code = request.args.get('code')
    data = {
        'grant_type': 'authorization_code',
        'code': code,
        'redirect_uri': url_for('callback', _external=True),
        'client_id': CLIENT_ID,
        'client_secret': CLIENT_SECRET
    }
    response = requests.post(TOKEN_URL, data=data)
    if response.status_code == 200:
        access_token = response.json().get('access_token')
        session['access_token'] = access_token
        return redirect(url_for('protected'))
    else:
        return 'Failed to get access token', 500

@app.route('/protected')
def protected():
    if 'access_token' not in session:
        return redirect(url_for('login'))
    return f'Welcome! Access Token: {session["access_token"]}'

if __name__ == '__main__':
    app.run(debug=True)